use bevy::prelude::*;

/// All the tunables of the cloud skybox demo, driven by the egui sliders.
#[derive(Resource, Clone, Debug, PartialEq)]
pub struct CloudSkySettings {
    /// Hour of the day, 0..24. Sunrise ~6, noon 13, sunset ~19.
    pub time_of_day: f32,
    /// Wind scroll speed of the cloud layers (uv units / second).
    pub wind_speed: f32,
    /// Wind direction in degrees (0 = +X, 90 = +Z).
    pub wind_direction_deg: f32,
    /// Global scale multiplier for the cloud noise.
    pub cloud_scale: f32,

    /// Coverage of the puffy low-altitude cumulus layer (0..1).
    pub cumulus_amount: f32,
    /// FBM octaves for the cumulus layer (1..8).
    pub cumulus_detail: f32,

    /// Coverage of the wispy high-altitude cirrus veil (0..1).
    pub cirrus_amount: f32,
    /// FBM octaves for the cirrus layer (1..8).
    pub cirrus_detail: f32,

    /// Coverage of the dark low storm layer (0..1).
    pub storm_amount: f32,
    /// FBM octaves for the storm layer (1..8).
    pub storm_detail: f32,

    /// Rain streak intensity (0..1).
    pub rain_intensity: f32,
    /// Snow flake intensity (0..1).
    pub snow_intensity: f32,

    /// Opacity of the cloud shadows projected on the ground (0..1).
    pub cloud_shadow_intensity: f32,
}

impl Default for CloudSkySettings {
    fn default() -> Self {
        Self {
            time_of_day: 14.5,
            wind_speed: 0.02,
            wind_direction_deg: 45.0,
            cloud_scale: 0.23,
            cumulus_amount: 0.55,
            cumulus_detail: 7.0,
            cirrus_amount: 0.45,
            cirrus_detail: 7.0,
            storm_amount: 0.5,
            storm_detail: 7.6,
            rain_intensity: 0.0,
            snow_intensity: 0.0,
            cloud_shadow_intensity: 0.35,
        }
    }
}

impl CloudSkySettings {
    /// Direction from a point on the ground toward the sun, plus a 0..1
    /// "day factor" (0 = deep night, 1 = full day), derived from `time_of_day`.
    pub fn sun_dir_and_day_factor(&self) -> (Vec3, f32) {
        let t = (self.time_of_day - 6.0) / 12.0 * std::f32::consts::PI;
        let elevation_sin = t.sin();
        // Azimuth sweeps east -> west over the day.
        let azimuth = (self.time_of_day - 12.0) / 12.0 * std::f32::consts::PI;
        let cos_el = elevation_sin.max(0.02).sqrt(); // cheap flattening near horizon
        let sun_dir = Vec3::new(
            azimuth.sin() * cos_el,
            elevation_sin.max(-1.0),
            -azimuth.cos() * cos_el,
        )
        .normalize_or_zero();
        let day_factor = smoothstep(-0.05, 0.15, elevation_sin);
        (sun_dir, day_factor)
    }

    /// Wind scroll vector in uv units / second.
    pub fn wind_vec(&self) -> Vec2 {
        let rad = self.wind_direction_deg.to_radians();
        Vec2::new(rad.cos(), rad.sin()) * self.wind_speed
    }
}

fn smoothstep(edge0: f32, edge1: f32, x: f32) -> f32 {
    let t = ((x - edge0) / (edge1 - edge0)).clamp(0.0, 1.0);
    t * t * (3.0 - 2.0 * t)
}

use bevy::prelude::*;
use bevy::render::render_resource::{AsBindGroup, ShaderType};
use bevy::shader::ShaderRef;

/// Uniforms shared by the sky dome and the precipitation overlay.
///
/// Everything is packed into `Vec4`s so the struct stays 16-byte aligned
/// and WebGL2-friendly.
#[derive(Clone, Copy, ShaderType, Debug)]
pub struct SkyParamsUniform {
    /// xyz = direction toward the sun, w = day factor (0 night .. 1 day).
    pub sun_dir: Vec4,
    /// x = cumulus amount, y = cirrus amount, z = storm amount, w = overcast.
    pub amounts: Vec4,
    /// x = cumulus octaves, y = cirrus octaves, z = storm octaves, w = cloud scale.
    pub detail: Vec4,
    /// x = wind uv.x, y = wind uv.y (per second), z = rain intensity, w = snow intensity.
    pub wind: Vec4,
}

// Sky dome material: blue gradient + sun + 3 cloud layers, fully procedural.
#[derive(Asset, TypePath, AsBindGroup, Clone, Debug)]
pub struct SkyDomeMaterial {
    #[uniform(0)]
    pub params: SkyParamsUniform,
}

impl Material for SkyDomeMaterial {
    fn fragment_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/skybox_clouds.wgsl".into()
    }
    fn vertex_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/skybox_clouds.wgsl".into()
    }
    fn alpha_mode(&self) -> AlphaMode {
        // Opaque on purpose: the dome sits in the opaque phase (with depth
        // write off) so transparent overlays — rain/snow, ground shadow —
        // always draw on top of the sky. With Blend, the transparent phase
        // would sort the camera-centered dome last and it would cover them.
        AlphaMode::Opaque
    }
    fn enable_prepass() -> bool {
        false
    }
    fn enable_shadows() -> bool {
        false
    }
    fn specialize(
        _pipeline: &bevy::pbr::MaterialPipeline,
        descriptor: &mut bevy::render::render_resource::RenderPipelineDescriptor,
        _layout: &bevy::render::mesh::MeshVertexBufferLayoutRef,
        _key: bevy::pbr::MaterialPipelineKey<Self>,
    ) -> Result<(), bevy::render::render_resource::SpecializedMeshPipelineError> {
        descriptor.primitive.cull_mode = None;
        // Keep the depth test (ground occludes the sky) but don't write:
        // the dome behaves like geometry at infinity.
        if let Some(depth) = descriptor.depth_stencil.as_mut() {
            depth.depth_write_enabled = Some(false);
        }
        Ok(())
    }
}

// Camera-following overlay quad for rain/snow. No depth testing so the
// precipitation also draws in front of the world geometry.
#[derive(Asset, TypePath, AsBindGroup, Clone, Debug)]
pub struct PrecipOverlayMaterial {
    #[uniform(0)]
    pub params: SkyParamsUniform,
}

impl Material for PrecipOverlayMaterial {
    fn fragment_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/precip_overlay.wgsl".into()
    }
    fn vertex_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/precip_overlay.wgsl".into()
    }
    fn alpha_mode(&self) -> AlphaMode {
        AlphaMode::Blend
    }
    fn enable_prepass() -> bool {
        false
    }
    fn enable_shadows() -> bool {
        false
    }
    fn specialize(
        _pipeline: &bevy::pbr::MaterialPipeline,
        descriptor: &mut bevy::render::render_resource::RenderPipelineDescriptor,
        _layout: &bevy::render::mesh::MeshVertexBufferLayoutRef,
        _key: bevy::pbr::MaterialPipelineKey<Self>,
    ) -> Result<(), bevy::render::render_resource::SpecializedMeshPipelineError> {
        descriptor.primitive.cull_mode = None;
        // Keep the depth attachment format (the render pass has one) but
        // never test or write depth: precipitation draws over the world.
        if let Some(depth) = descriptor.depth_stencil.as_mut() {
            depth.depth_write_enabled = Some(false);
            depth.depth_compare = Some(bevy::render::render_resource::CompareFunction::Always);
        }
        Ok(())
    }
}

#[derive(Clone, Copy, ShaderType, Debug)]
pub struct GroundShadowUniform {
    /// x = intensity, y = uv scale, z/w = unused.
    pub params: Vec4,
    /// x/y = scroll speed (uv units per second), z/w = unused.
    pub wind: Vec4,
}

// Flat decal multiplying the ground with scrolling cloud shadows.
// The texture is generated on the CPU once at startup (see systems.rs).
#[derive(Asset, TypePath, AsBindGroup, Clone, Debug)]
pub struct CloudGroundShadowMaterial {
    #[uniform(0)]
    pub params: GroundShadowUniform,
    #[texture(1)]
    #[sampler(2)]
    pub texture: Handle<Image>,
}

impl Material for CloudGroundShadowMaterial {
    fn fragment_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/ground_shadow.wgsl".into()
    }
    fn vertex_shader() -> ShaderRef {
        "embedded://demo_resolution_selector_web_bevy/plugins/cloud_sky/ground_shadow.wgsl".into()
    }
    fn alpha_mode(&self) -> AlphaMode {
        AlphaMode::Blend
    }
    fn enable_prepass() -> bool {
        false
    }
    fn enable_shadows() -> bool {
        false
    }
    fn specialize(
        _pipeline: &bevy::pbr::MaterialPipeline,
        descriptor: &mut bevy::render::render_resource::RenderPipelineDescriptor,
        _layout: &bevy::render::mesh::MeshVertexBufferLayoutRef,
        _key: bevy::pbr::MaterialPipelineKey<Self>,
    ) -> Result<(), bevy::render::render_resource::SpecializedMeshPipelineError> {
        descriptor.primitive.cull_mode = None;
        Ok(())
    }
}

use bevy::asset::RenderAssetUsages;
use bevy::prelude::*;
use bevy::render::render_resource::{Extent3d, TextureDimension, TextureFormat};

use crate::plugins::pedestrians::pedestrian_controller_plugin::MainCamera;

use super::materials::{
    CloudGroundShadowMaterial, GroundShadowUniform, PrecipOverlayMaterial, SkyDomeMaterial,
    SkyParamsUniform,
};
use super::settings::CloudSkySettings;

/// Marker for the sky dome sphere.
#[derive(Component)]
pub struct CloudSkyDome;
/// Marker for the camera-following rain/snow overlay quad.
#[derive(Component)]
pub struct PrecipOverlayQuad;
/// Marker for the ground cloud-shadow decal.
#[derive(Component)]
pub struct CloudGroundShadowQuad;

/// Builds the shared uniform block from the UI settings.
pub fn make_sky_params(s: &CloudSkySettings) -> SkyParamsUniform {
    let (sun_dir, day_factor) = s.sun_dir_and_day_factor();
    let overcast = s
        .storm_amount
        .max(s.rain_intensity)
        .max(s.snow_intensity)
        .min(1.0);
    let wind = s.wind_vec();
    SkyParamsUniform {
        sun_dir: Vec4::new(sun_dir.x, sun_dir.y, sun_dir.z, day_factor),
        amounts: Vec4::new(s.cumulus_amount, s.cirrus_amount, s.storm_amount, overcast),
        detail: Vec4::new(
            s.cumulus_detail,
            s.cirrus_detail,
            s.storm_detail,
            s.cloud_scale,
        ),
        wind: Vec4::new(wind.x, wind.y, s.rain_intensity, s.snow_intensity),
    }
}

fn make_ground_shadow_params(s: &CloudSkySettings) -> GroundShadowUniform {
    let wind = s.wind_vec();
    GroundShadowUniform {
        // uv scale: the 512px tile spans ~333m of ground.
        params: Vec4::new(s.cloud_shadow_intensity, 0.003, 0.0, 0.0),
        wind: Vec4::new(wind.x * 60.0, wind.y * 60.0, 0.0, 0.0),
    }
}

pub fn setup_cloud_sky(
    mut commands: Commands,
    settings: Res<CloudSkySettings>,
    mut meshes: ResMut<Assets<Mesh>>,
    mut images: ResMut<Assets<Image>>,
    mut sky_mats: ResMut<Assets<SkyDomeMaterial>>,
    mut precip_mats: ResMut<Assets<PrecipOverlayMaterial>>,
    mut shadow_mats: ResMut<Assets<CloudGroundShadowMaterial>>,
) {
    let params = make_sky_params(&settings);

    // Sky dome: big sphere centered on (and following) the camera, rendered
    // double-sided so we see its inside faces.
    commands.spawn((
        Name::new("CloudSkyDome"),
        CloudSkyDome,
        Mesh3d(meshes.add(Sphere::new(800.0).mesh().uv(64, 32))),
        MeshMaterial3d(sky_mats.add(SkyDomeMaterial { params })),
        Transform::from_xyz(-10.0, 2.0, -15.0),
    ));

    // Precipitation overlay: quad held 2m in front of the camera, no depth
    // testing, so rain/snow draw over the whole view.
    commands.spawn((
        Name::new("PrecipOverlay"),
        PrecipOverlayQuad,
        Mesh3d(meshes.add(Rectangle::new(6.0, 4.0))),
        MeshMaterial3d(precip_mats.add(PrecipOverlayMaterial { params })),
        Transform::from_xyz(-10.0, 2.0, -13.0),
    ));

    // Ground cloud shadows: flat decal over the debug-scene ground.
    let shadow_texture = images.add(generate_cloud_shadow_image());
    commands.spawn((
        Name::new("CloudGroundShadow"),
        CloudGroundShadowQuad,
        Mesh3d(meshes.add(Rectangle::new(1000.0, 1000.0))),
        MeshMaterial3d(shadow_mats.add(CloudGroundShadowMaterial {
            params: make_ground_shadow_params(&settings),
            texture: shadow_texture,
        })),
        Transform::from_xyz(0.0, 0.15, 0.0)
            .with_rotation(Quat::from_rotation_x(-std::f32::consts::FRAC_PI_2)),
    ));
}

/// Keep the dome centered on the camera and the overlay pinned in front of it.
pub fn follow_camera(
    camera_q: Query<&GlobalTransform, With<MainCamera>>,
    mut dome_q: Query<&mut Transform, (With<CloudSkyDome>, Without<PrecipOverlayQuad>)>,
    mut overlay_q: Query<&mut Transform, (With<PrecipOverlayQuad>, Without<CloudSkyDome>)>,
) {
    let Ok(cam) = camera_q.single() else {
        return;
    };
    let (_, rot, pos) = cam.to_scale_rotation_translation();
    for mut t in dome_q.iter_mut() {
        t.translation = pos;
    }
    let fwd: Vec3 = cam.forward().into();
    for mut t in overlay_q.iter_mut() {
        t.translation = pos + fwd * 2.0;
        t.rotation = rot;
    }
}

/// Push slider values into the material assets whenever the UI changes them.
pub fn sync_sky_uniforms(
    settings: Res<CloudSkySettings>,
    mut sky_mats: ResMut<Assets<SkyDomeMaterial>>,
    mut precip_mats: ResMut<Assets<PrecipOverlayMaterial>>,
    mut shadow_mats: ResMut<Assets<CloudGroundShadowMaterial>>,
) {
    if !settings.is_changed() {
        return;
    }
    let params = make_sky_params(&settings);
    for (_, mat) in sky_mats.iter_mut() {
        mat.params = params;
    }
    for (_, mat) in precip_mats.iter_mut() {
        mat.params = params;
    }
    let shadow_params = make_ground_shadow_params(&settings);
    for (_, mat) in shadow_mats.iter_mut() {
        mat.params = shadow_params;
    }
}

/// Match the debug scene's sun + ambient light to the time-of-day slider so
/// the world lighting agrees with the sky.
pub fn sync_sun_light(
    settings: Res<CloudSkySettings>,
    mut light_q: Query<(&mut Transform, &mut DirectionalLight)>,
    mut ambient_q: Query<&mut AmbientLight>,
) {
    let (sun_dir, day_factor) = settings.sun_dir_and_day_factor();
    let mut light_dir = sun_dir;
    light_dir.y = light_dir.y.max(0.08);
    for (mut transform, mut light) in light_q.iter_mut() {
        *transform = Transform::from_translation(light_dir.normalize_or_zero() * 100.0)
            .looking_at(Vec3::ZERO, Vec3::Y);
        light.illuminance = 30.0 + 3470.0 * day_factor;
    }
    for mut ambient in ambient_q.iter_mut() {
        ambient.brightness = 150.0 + 850.0 * day_factor;
    }
}

// ---------------------------------------------------------------------------
// CPU cloud-shadow texture generation
// ---------------------------------------------------------------------------

const SHADOW_TEX_SIZE: usize = 512;

fn hash2i(x: i32, y: i32) -> f32 {
    let mut h = (x as u32)
        .wrapping_mul(0x8da6_b343)
        .wrapping_add((y as u32).wrapping_mul(0xd816_3841))
        .wrapping_add(0xcb1a_b31f);
    h = h.wrapping_mul(0x9e37_79b1);
    h ^= h >> 15;
    h = h.wrapping_mul(0x85eb_ca6b);
    h ^= h >> 13;
    (h & 0x00ff_ffff) as f32 / 16_777_216.0
}

/// Tileable value noise: the lattice is wrapped modulo `period` so the
/// texture repeats seamlessly.
fn vnoise_periodic(x: f32, y: f32, period: i32) -> f32 {
    let xi = x.floor() as i32;
    let yi = y.floor() as i32;
    let xf = x - xi as f32;
    let yf = y - yi as f32;
    let u = xf * xf * (3.0 - 2.0 * xf);
    let v = yf * yf * (3.0 - 2.0 * yf);
    let w = |i: i32| i.rem_euclid(period);
    let a = hash2i(w(xi), w(yi));
    let b = hash2i(w(xi + 1), w(yi));
    let c = hash2i(w(xi), w(yi + 1));
    let d = hash2i(w(xi + 1), w(yi + 1));
    a + (b - a) * u + (c - a) * v + (a - b - c + d) * u * v
}

fn smoothstep_cpu(e0: f32, e1: f32, x: f32) -> f32 {
    let t = ((x - e0) / (e1 - e0)).clamp(0.0, 1.0);
    t * t * (3.0 - 2.0 * t)
}

/// Generates a tileable grayscale FBM image: white where clouds are
/// (the shader turns that into dark shadow alpha).
pub fn generate_cloud_shadow_image() -> Image {
    let mut data = vec![0u8; SHADOW_TEX_SIZE * SHADOW_TEX_SIZE * 4];
    for y in 0..SHADOW_TEX_SIZE {
        for x in 0..SHADOW_TEX_SIZE {
            let u = x as f32 / SHADOW_TEX_SIZE as f32;
            let v = y as f32 / SHADOW_TEX_SIZE as f32;
            // 6 octaves, base period 4 cells across the tile.
            let mut sum = 0.0f32;
            let mut amp = 0.5f32;
            let mut period = 4i32;
            for _ in 0..6 {
                sum += amp * vnoise_periodic(u * period as f32, v * period as f32, period);
                amp *= 0.5;
                period *= 2;
            }
            // sum in ~[0, 0.97]; remap through a coverage curve so shadows
            // form distinct cloud-shaped blobs.
            let n = smoothstep_cpu(0.35, 0.75, sum);
            let g = (n * 255.0) as u8;
            let off = (y * SHADOW_TEX_SIZE + x) * 4;
            data[off] = g;
            data[off + 1] = g;
            data[off + 2] = g;
            data[off + 3] = 255;
        }
    }
    let mut image = Image::new_fill(
        Extent3d {
            width: SHADOW_TEX_SIZE as u32,
            height: SHADOW_TEX_SIZE as u32,
            depth_or_array_layers: 1,
        },
        TextureDimension::D2,
        &data,
        TextureFormat::Rgba8UnormSrgb,
        RenderAssetUsages::default(),
    );
    image.sampler = bevy::image::ImageSampler::Descriptor(bevy::image::ImageSamplerDescriptor {
        address_mode_u: bevy::image::ImageAddressMode::Repeat,
        address_mode_v: bevy::image::ImageAddressMode::Repeat,
        ..default()
    });
    image
}

use bevy::prelude::*;
use bevy_egui::{EguiContexts, egui};

use super::settings::CloudSkySettings;
use crate::ui_egui::UiState;

/// Control window for the cloud sky. Opened from the Debug menu in the main
/// game; always open in the `clouds` demo binary.
pub fn cloud_sky_window(
    mut contexts: EguiContexts,
    mut ui_state: ResMut<UiState>,
    mut settings: ResMut<CloudSkySettings>,
) {
    let Ok(ctx) = contexts.ctx_mut() else {
        return;
    };
    if !ui_state.show_clouds_sky {
        return;
    }

    egui::Window::new("☁ Clouds & Sky")
        .open(&mut ui_state.show_clouds_sky)
        .default_width(300.0)
        .show(ctx, |ui| {
            let s = &mut *settings;

            ui.collapsing("Sky", |ui| {
                ui.add(egui::Slider::new(&mut s.time_of_day, 0.0..=24.0).text("Time of day"));
                ui.add(
                    egui::Slider::new(&mut s.wind_speed, 0.0..=0.2)
                        .text("Wind speed")
                        .step_by(0.001),
                );
                ui.add(
                    egui::Slider::new(&mut s.wind_direction_deg, 0.0..=360.0)
                        .text("Wind direction"),
                );
                ui.add(egui::Slider::new(&mut s.cloud_scale, 0.2..=3.0).text("Cloud scale"));
            });

            ui.collapsing("Cumulus (puffy)", |ui| {
                ui.add(egui::Slider::new(&mut s.cumulus_amount, 0.0..=1.0).text("Amount"));
                ui.add(egui::Slider::new(&mut s.cumulus_detail, 1.0..=8.0).text("Detail"));
            });

            ui.collapsing("Cirrus (wispy)", |ui| {
                ui.add(egui::Slider::new(&mut s.cirrus_amount, 0.0..=1.0).text("Amount"));
                ui.add(egui::Slider::new(&mut s.cirrus_detail, 1.0..=8.0).text("Detail"));
            });

            ui.collapsing("Storm (dark)", |ui| {
                ui.add(egui::Slider::new(&mut s.storm_amount, 0.0..=1.0).text("Amount"));
                ui.add(egui::Slider::new(&mut s.storm_detail, 1.0..=8.0).text("Detail"));
            });

            ui.collapsing("Precipitation", |ui| {
                ui.add(egui::Slider::new(&mut s.rain_intensity, 0.0..=1.0).text("Rain"));
                ui.add(egui::Slider::new(&mut s.snow_intensity, 0.0..=1.0).text("Snow"));
            });

            ui.collapsing("Ground shadow", |ui| {
                ui.add(
                    egui::Slider::new(&mut s.cloud_shadow_intensity, 0.0..=1.0)
                        .text("Shadow intensity"),
                );
            });
        });
}

//! Procedural sky plugin: blue-sky gradient, sun, day/night cycle, three
//! cloud layer types (cumulus / cirrus / storm), rain & snow overlay and
//! scrolling cloud shadows on the ground — all WebGL2-safe custom WGSL.

use bevy::asset::embedded_asset;
use bevy::prelude::*;
use bevy_egui::EguiPrimaryContextPass;

pub mod materials;
pub mod settings;
pub mod systems;
pub mod ui;

use materials::{CloudGroundShadowMaterial, PrecipOverlayMaterial, SkyDomeMaterial};
use settings::CloudSkySettings;
use systems::{follow_camera, setup_cloud_sky, sync_sky_uniforms, sync_sun_light};
use ui::cloud_sky_window;

pub struct CloudSkyPlugin;

impl Plugin for CloudSkyPlugin {
    fn build(&self, app: &mut App) {
        embedded_asset!(app, "skybox_clouds.wgsl");
        embedded_asset!(app, "precip_overlay.wgsl");
        embedded_asset!(app, "ground_shadow.wgsl");

        app.init_resource::<CloudSkySettings>()
            // Binaries that pull this plugin in via `SetupDebugScenePlugin`
            // don't have `UiEguiPlugin`, so make sure the resource exists.
            .init_resource::<crate::ui_egui::UiState>()
            .add_plugins(MaterialPlugin::<SkyDomeMaterial>::default())
            .add_plugins(MaterialPlugin::<PrecipOverlayMaterial>::default())
            .add_plugins(MaterialPlugin::<CloudGroundShadowMaterial>::default())
            .add_systems(Startup, setup_cloud_sky)
            .add_systems(Update, (follow_camera, sync_sky_uniforms, sync_sun_light));

        app.add_systems(EguiPrimaryContextPass, cloud_sky_window);
    }
}

// Procedural sky dome: blue-sky gradient, sun, day/night, and three analytic
// cloud layers (cumulus / cirrus / storm). WebGL2-safe: textureless hash
// noise, a single uniform binding, no storage buffers / compute.

#import bevy_pbr::mesh_functions::get_world_from_local
#import bevy_pbr::mesh_view_bindings::{view, globals}

struct SkyParams {
    sun_dir: vec4<f32>, // xyz = direction toward sun, w = day factor (0..1)
    amounts: vec4<f32>, // x = cumulus, y = cirrus, z = storm, w = overcast
    detail: vec4<f32>,  // x/y/z = FBM octaves per layer, w = cloud scale
    wind: vec4<f32>,    // xy = wind uv scroll / s, z = rain, w = snow
};
@group(#{MATERIAL_BIND_GROUP}) @binding(0) var<uniform> u: SkyParams;

struct VertexOutput {
    @builtin(position) clip: vec4<f32>,
    @location(0) world_pos: vec3<f32>,
};

@vertex
fn vertex(@location(0) pos: vec3<f32>,
          @builtin(instance_index) inst: u32) -> VertexOutput {
    let model = get_world_from_local(inst);
    let world_pos = (model * vec4<f32>(pos, 1.0)).xyz;
    var out: VertexOutput;
    out.world_pos = world_pos;
    out.clip = view.clip_from_world * vec4<f32>(world_pos, 1.0);
    return out;
}

// ---------------------------------------------------------------------------
// Noise (hash-based value noise + FBM with octave rotation, no textures)
// ---------------------------------------------------------------------------

fn hash2(p: vec2<f32>) -> f32 {
    return fract(sin(dot(p, vec2<f32>(127.1, 311.7))) * 43758.5453);
}

fn vnoise(p: vec2<f32>) -> f32 {
    let i = floor(p);
    let f = fract(p);
    let a = hash2(i);
    let b = hash2(i + vec2<f32>(1.0, 0.0));
    let c = hash2(i + vec2<f32>(0.0, 1.0));
    let d = hash2(i + vec2<f32>(1.0, 1.0));
    // quintic smoothing (smoother gradients than cubic Hermite)
    let w = f * f * f * (f * (f * 6.0 - 15.0) + 10.0);
    return mix(mix(a, b, w.x), mix(c, d, w.x), w.y);
}

// FBM in ~[0, 1). `octaves` is a uniform, so loop to a compile-time max and
// break — legal in WGSL and GLSL ES 3.0.
fn fbm(p_in: vec2<f32>, octaves: f32) -> f32 {
    var p = p_in;
    var sum = 0.0;
    var amp = 0.5;
    var norm = 0.0;
    let rot = mat2x2<f32>(vec2<f32>(0.8, -0.6), vec2<f32>(0.6, 0.8));
    for (var i = 0; i < 8; i++) {
        if (f32(i) >= octaves) { break; }
        sum += amp * vnoise(p);
        norm += amp;
        p = rot * p * 2.03;
        amp *= 0.5;
    }
    return sum / max(norm, 1e-4);
}

// ---------------------------------------------------------------------------
// Sky background
// ---------------------------------------------------------------------------

fn sky_color(rd: vec3<f32>, sun_dir: vec3<f32>, day: f32, overcast: f32) -> vec3<f32> {
    let elev = clamp(rd.y, 0.0, 1.0);
    let g = pow(elev, 0.55);

    // day gradient: light blue horizon -> deep blue zenith
    let day_col = mix(vec3<f32>(0.62, 0.76, 0.95), vec3<f32>(0.10, 0.32, 0.85), g);
    // night gradient: dark blue
    let night_col = mix(vec3<f32>(0.05, 0.08, 0.16), vec3<f32>(0.01, 0.02, 0.06), g);
    var col = mix(night_col, day_col, day);

    let sundot = clamp(dot(rd, sun_dir), 0.0, 1.0);
    // warm glow around the sun, stronger when the sun is low
    let low_sun = 1.0 - clamp(sun_dir.y * 2.5, 0.0, 1.0);
    let warm = mix(vec3<f32>(1.0, 0.9, 0.7), vec3<f32>(1.0, 0.55, 0.25), low_sun);
    col += warm * pow(sundot, 8.0) * 0.30 * day;
    col += warm * pow(sundot, 64.0) * 0.45 * day;
    // sun disc
    col += vec3<f32>(1.0, 0.95, 0.85) * pow(sundot, 1800.0) * 8.0 * day;

    // stars at night
    if (day < 0.35 && rd.y > 0.02) {
        let sp = floor(rd.xz / max(rd.y, 0.1) * 140.0);
        let star = step(0.996, hash2(sp));
        let twinkle = 0.6 + 0.4 * sin(globals.time * 3.0 + hash2(sp + 7.7) * 40.0);
        col += vec3<f32>(0.9, 0.95, 1.0) * star * twinkle * (0.35 - day) * 1.6;
    }

    // overcast: flatten toward gray
    let gray = vec3<f32>(0.38, 0.40, 0.45) * (0.15 + 0.85 * day);
    return mix(col, gray, overcast * 0.75);
}

// ---------------------------------------------------------------------------
// Cloud layers — each returns vec4(rgb, alpha)
// ---------------------------------------------------------------------------

fn wind_scroll() -> vec2<f32> {
    return u.wind.xy * globals.time;
}

fn layer_uv(rd: vec3<f32>, h: f32, scale: f32) -> vec2<f32> {
    let t = min((h - view.world_position.y) / max(rd.y, 0.03), 25000.0);
    let hit = view.world_position + rd * t;
    return hit.xz * scale * u.detail.w + wind_scroll();
}

fn cumulus_layer(rd: vec3<f32>, sundot: f32) -> vec4<f32> {
    let amount = u.amounts.x;
    if (amount <= 0.001) { return vec4<f32>(0.0); }
    let uv = layer_uv(rd, 200.0, 0.0016);
    // cheap domain warp for puffy, non-grid shapes
    let w = vec2<f32>(vnoise(uv * 2.1 + 11.3), vnoise(uv * 2.1 + 47.1));
    let n = fbm(uv + 0.4 * w, u.detail.x);
    let cov = 1.0 - amount;
    let dens = smoothstep(cov, cov + 0.4, n);
    if (dens <= 0.001) { return vec4<f32>(0.0); }

    // cheap directional lighting: one extra FBM sample toward the sun
    let sun_xz = normalize(u.sun_dir.xz + vec2<f32>(1e-4, 0.0));
    let n2 = fbm(uv + 0.4 * w + sun_xz * 0.12, max(u.detail.x - 2.0, 1.0));
    let dif = clamp((n - n2) * 6.0, -1.0, 1.0);

    let day = u.sun_dir.w;
    let lit = vec3<f32>(1.0, 0.98, 0.95) * (0.15 + 0.85 * day);
    let shaded = vec3<f32>(0.55, 0.58, 0.68) * (0.15 + 0.85 * day);
    var col = mix(shaded, lit, 0.5 + 0.5 * dif);
    // darker bottoms for thick clouds
    col *= mix(1.0, 0.62, dens * (1.0 - 0.5 * dif));
    // silver lining on thin edges facing the sun
    let edge = dens * (1.0 - dens) * 4.0;
    col += vec3<f32>(1.0, 0.85, 0.65) * pow(sundot, 5.0) * edge * 0.35 * day;
    return vec4<f32>(col, dens * 0.95);
}

fn cirrus_layer(rd: vec3<f32>, day: f32) -> vec4<f32> {
    let amount = u.amounts.y;
    if (amount <= 0.001) { return vec4<f32>(0.0); }
    // anisotropic uv -> long streaky wisps; slower wind
    let t = min((800.0 - view.world_position.y) / max(rd.y, 0.03), 25000.0);
    let hit = view.world_position + rd * t;
    let uv2 = hit.xz * vec2<f32>(0.00045, 0.0015) * u.detail.w + wind_scroll() * 0.5;
    let warp = vec2<f32>(vnoise(uv2 * 3.1), vnoise(uv2 * 3.1 + 31.7));
    let n = fbm(uv2 + 0.9 * warp, u.detail.y);
    let cov = 1.0 - amount * 0.85;
    let a = smoothstep(cov, cov + 0.5, n) * 0.4 * amount;
    if (a <= 0.001) { return vec4<f32>(0.0); }
    let col = vec3<f32>(0.92, 0.94, 1.0) * (0.1 + 0.9 * day);
    return vec4<f32>(col, a);
}

fn storm_layer(rd: vec3<f32>, day: f32) -> vec4<f32> {
    let amount = u.amounts.z;
    if (amount <= 0.001) { return vec4<f32>(0.0); }
    let t = min((140.0 - view.world_position.y) / max(rd.y, 0.03), 25000.0);
    let hit = view.world_position + rd * t;
    let uv = hit.xz * 0.0007 * u.detail.w + wind_scroll() * 1.6;
    let n = fbm(uv, u.detail.z);
    let cov = 1.0 - amount;
    let dens = smoothstep(cov, cov + 0.55, n);
    if (dens <= 0.001) { return vec4<f32>(0.0); }
    let top = vec3<f32>(0.48, 0.50, 0.56) * (0.1 + 0.9 * day);
    let bottom = vec3<f32>(0.16, 0.17, 0.21) * (0.1 + 0.9 * day);
    let col = mix(top, bottom, dens);
    return vec4<f32>(col, dens * 0.98);
}

// ---------------------------------------------------------------------------

@fragment
fn fragment(in: VertexOutput) -> @location(0) vec4<f32> {
    let cam = view.world_position;
    let rd = normalize(in.world_pos - cam);
    let sun_dir = normalize(u.sun_dir.xyz);
    let day = u.sun_dir.w;
    let overcast = u.amounts.w;
    let sundot = clamp(dot(rd, sun_dir), 0.0, 1.0);

    var col = sky_color(rd, sun_dir, day, overcast);

    // clouds only above the horizon; fade them into the haze near it
    if (rd.y > 0.005) {
        let horizon_fade = smoothstep(0.005, 0.10, rd.y);
        // back to front: cirrus (highest) -> cumulus -> storm (lowest)
        let cir = cirrus_layer(rd, day);
        col = mix(col, cir.rgb, cir.a * horizon_fade);
        let cum = cumulus_layer(rd, sundot);
        col = mix(col, cum.rgb, cum.a * horizon_fade);
        let sto = storm_layer(rd, day);
        col = mix(col, sto.rgb, sto.a * horizon_fade);
    }

    return vec4<f32>(col, 1.0);
}

// Rain / snow overlay. Drawn on a quad held 2m in front of the camera with
// depth testing disabled, so precipitation covers the whole view.
// WebGL2-safe: pure hash noise, one uniform binding.

#import bevy_pbr::mesh_functions::get_world_from_local
#import bevy_pbr::mesh_view_bindings::{view, globals}

struct SkyParams {
    sun_dir: vec4<f32>, // xyz = direction toward sun, w = day factor
    amounts: vec4<f32>, // x = cumulus, y = cirrus, z = storm, w = overcast
    detail: vec4<f32>,  // per-layer octaves + cloud scale
    wind: vec4<f32>,    // xy = wind scroll, z = rain intensity, w = snow intensity
};
@group(#{MATERIAL_BIND_GROUP}) @binding(0) var<uniform> u: SkyParams;

struct VertexOutput {
    @builtin(position) clip: vec4<f32>,
    @location(0) world_pos: vec3<f32>,
};

@vertex
fn vertex(@location(0) pos: vec3<f32>,
          @builtin(instance_index) inst: u32) -> VertexOutput {
    let model = get_world_from_local(inst);
    let world_pos = (model * vec4<f32>(pos, 1.0)).xyz;
    var out: VertexOutput;
    out.world_pos = world_pos;
    out.clip = view.clip_from_world * vec4<f32>(world_pos, 1.0);
    return out;
}

fn hash2(p: vec2<f32>) -> f32 {
    return fract(sin(dot(p, vec2<f32>(127.1, 311.7))) * 43758.5453);
}

// Rain: thin, elongated, slightly wind-slanted streaks on a hashed column
// grid over (yaw, pitch).
fn rain(rd: vec3<f32>, intensity: f32, day: f32) -> f32 {
    let yaw = atan2(rd.x, rd.z);
    // slant: columns shift with pitch so streaks lean along the wind
    let slant = (u.wind.x + u.wind.y) * 6.0 + 0.15;
    let p_yaw = yaw + rd.y * slant;
    let cols = 70.0;
    let col_id = floor(p_yaw * cols);
    let rnd = hash2(vec2<f32>(col_id, 3.7));
    // only a subset of columns carries a streak
    if (rnd > intensity * 0.5) { return 0.0; }
    // very thin horizontally
    let cx = abs(fract(p_yaw * cols) - 0.5);
    let thin = smoothstep(0.10, 0.03, cx);
    if (thin <= 0.001) { return 0.0; }
    // fall animation: pitch scrolls downward fast, per-column speed/offset.
    // Long tail + quick head fade -> elongated streak, not a square dash.
    let speed = 2.5 + rnd * 2.0;
    let span = 4.0 + rnd * 3.0;
    let phase = fract(rd.y * span + globals.time * speed + rnd * 40.0);
    let streak = smoothstep(0.0, 0.02, phase) * smoothstep(0.60, 0.35, phase);
    return thin * streak * intensity;
}

// Snow: soft drifting dots on a hashed cell grid over (yaw, pitch).
fn snow(rd: vec3<f32>, intensity: f32, day: f32) -> f32 {
    let yaw = atan2(rd.x, rd.z);
    let grid = vec2<f32>(yaw * 36.0, rd.y * 24.0);
    let drift = globals.time * 0.55;
    // slow fall + sideways wobble
    let p = vec2<f32>(grid.x + sin(drift + grid.y * 2.0) * 0.15, grid.y + drift);
    let cell = floor(p);
    let rnd = hash2(cell);
    if (rnd > intensity * 0.5) { return 0.0; }
    let center = vec2<f32>(hash2(cell + 1.3), hash2(cell + 5.1));
    let d = length(fract(p) - center);
    let flake = smoothstep(0.10, 0.02, d);
    return flake * intensity;
}

@fragment
fn fragment(in: VertexOutput) -> @location(0) vec4<f32> {
    let rain_amt = u.wind.z;
    let snow_amt = u.wind.w;
    if (rain_amt <= 0.001 && snow_amt <= 0.001) { discard; }

    let rd = normalize(in.world_pos - view.world_position);
    let day = u.sun_dir.w;
    let r = rain(rd, rain_amt, day);
    let s = snow(rd, snow_amt, day);
    if (r + s <= 0.001) { discard; }

    let rain_col = vec3<f32>(0.65, 0.72, 0.85) * (0.2 + 0.8 * day);
    let snow_col = vec3<f32>(0.95, 0.96, 1.0) * (0.25 + 0.75 * day);
    let col = rain_col * r + snow_col * s;
    return vec4<f32>(col, clamp(r * 0.55 + s * 0.9, 0.0, 1.0));
}

